def lcs_length(a,b):
    # dynamic programming LCS length
    a = normalize_ar(a)
    b = normalize_ar(b)
    n, m = len(a), len(b)
    # optimize memory
    dp = [0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            temp = dp[j]
            if a[i-1]==b[j-1]:
                dp[j] = prev+1
            else:
                if dp[j] < dp[j-1]:
                    dp[j] = dp[j-1]
            prev = temp
    return dp[m]

def lcs_ratio(a,b):
    l = lcs_length(a,b)
    denom = len(normalize_ar(a))
    return l/denom if denom>0 else 0

