def longest_common_substring(a, b):
    a = normalize_ar(a)
    b = normalize_ar(b)
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    max_len = 0
    end_pos = 0
    for i in range(1,n+1):
        new = [0]*(m+1)
        for j in range(1,m+1):
            if a[i-1] == b[j-1]:
                new[j] = dp[j-1] + 1
                if new[j] > max_len:
                    max_len = new[j]
                    end_pos = i
        dp = new
    return max_len, a[end_pos-max_len:end_pos]

def lcsstr_ratio(a,b):
    L, s = longest_common_substring(a,b)
    return L/len(normalize_ar(a)) if len(normalize_ar(a))>0 else 0

